solutions.javascript:
// Define a function to correct the media query priority
function correctMediaQueryPriority(css)
{
	// Split the CSS file into media queries
	let mediaQueries = css.split('@media');
	// Sort the media queries based on the features
	mediaQueries.sort((a, b) => {
		// Extract the features from the media query
		let featuresA = a.split('and')[1].trim().split(' '); 
		let featuresB = b.split('and')[1].trim().split(' ');
		// Sort the features alphabetically
		featuresA.sort();
		featuresB.sort();
		// Compare the sorted features
		return featuresA.join(' ') < featuresB.join(' ');
	});
	// Join the sorted media queries back into a string
	return '@media ' + mediaQueries.join('@media ');
}

solutions.python:
class Solution:
  def correctMediaQueryPriority(self, css):
    # Split the CSS file into media queries
    media_queries = css.split('@media');
    # Sort the media queries based on the features
    media_queries.sort(key=lambda x: ' '.join([feature for feature in x.split('and')[1].split(' ') if feature != 'and']));
    # Join the sorted media queries back into a string
    return '@media ' + '@media '.join(media_queries)

